@startuml

class Princesa {
  + Princesa(string n);
  + Princesa(const Princesa& p)
  + void gritar()
}

class Villano {
  + Villano(string n);
  + Villano(const Villano& v)
  + void secuestrar()
}

class Heroe {
  + Heroe(string n);
  + Heroe(const Heroe& h)
  + void salvar()
}

class SubClase <<template>> {
  + T*clone()
}

class Mundo {
  ~ string nombreMundo
  + Mundo(string nombreMundo)
}

abstract class Personaje <<abstract>> {
  ~ string nombre;
  ~ string correo;
  ~ int telefono;
  ~ Mundo* mundo;
  + Personaje ();
  + Personaje(string nombre)
  + virtual Personaje* clone();
}

Princesa --|> SubClase
Villano --|> SubClase
Heroe --|> SubClase

SubClase ..|> Personaje

Mundo --* Personaje

@enduml
